import styled from 'styled-components';

export const SkillsContainer = styled.section`
background: rgba(80,96,216, .4);
height:100%;
margin:0;

    .title {
        position: absolute;
        top: 0;
        left: 50%;
        text-align: center;
        text-transform: uppercase;
        display: block;
        font-weight: 700;
        letter-spacing: 0.25em;
        font-size: 0.9em;
        width: 25em;
        height: 3.25em;
        top: -3.25em;
        line-height: 3.25em;
        margin-bottom: -3.25em;
        margin-left: -12.5em;
        padding-top: 0.5em;
    }

    .title:before {
        content: '';
        position: absolute;
        bottom: -38px;
        left: -35px;
        width: 35px;
        height: 38px;
    }


`
